INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-d0d1b9a2-moex-00220', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '有關查核人員辨認查核證據之文件真實性，下列敘述何者錯誤？', '["查核人員對所取得查核證據，甚少涉及辨認其真實性，亦未受此訓練，因此不被預期成為辨認 文件真實性專家", "查核人員亦可能因管理階層或第三人隱匿相關附屬協議，致無法偵查出文件條款已被修改", "查核人員通常假設所取得之紀錄及文件非屬真實，除非有理由相信其與事實相符", "查核人員所取得之資訊，應考量其作為查核證據之可靠性，包括考量產生及維護該資訊之相關 控制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00221', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '有關重大性之敘述，下列何者正確？', '["對於重大性所作之判斷僅受不實表達金額之影響", "某一事項對財務報表使用者而言是否屬重大之判斷，通常係以一般使用者對財務資訊之需求為 考量依據", "僅不實表達之個別金額可合理預期將影響財務報表使用者所作之經濟決策，才能被認為具有重 大性", "重大不實表達風險係指財務報表存有重大不實表達時，查核人員出具不適當查核報告之風險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00222', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依審計準則620號「採用查核人員專家之工作」之規定，如會計或審計領域以外之專門知識對取 得足夠及適切之查核證據係屬必要，查核人員應決定是否採用查核人員專家之工作。下列敘述何 者錯誤？', '["查核人員與查核人員外部專家間之協議通常採委任書之形式", "查核人員適用之職業道德規範之保密條款亦適用於查核人員專家", "會計師得於無保留意見之查核報告之查核意見段及查核意見之基礎段中提及查核人員專家之 工作", "對客觀性產生威脅之程度及是否需要防護措施之評估，可能取決於查核人員專家於查核中之角 色及其工作對查核之重要性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00223', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '會計師接受客戶之首次委任，對於期初存貨的金額無法取得足夠適切的證據，且認為其影響係屬 重大但未達廣泛，除此之外，會計師皆已取得足夠適切的證據支持財務報表未存有重大不實表達， 則會計師對當期財務報表如何表示意見？', '["對整體財務報表表示保留意見", "對整體財務報表表示無保留意見，並納入強調事項段說明", "對資產負債表表示無保留意見，但對綜合損益表、權益變動表及現金流量表表示保留意見", "對資產負債表及現金流量表表示無保留意見，但對綜合損益表及權益變動表表示保留意見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00224', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依審計準則600號「集團財務報表查核之特別考量」之規定，下列敘述何者錯誤？', '["集團主辦會計師應複核集團整體查核策略及集團查核計畫", "於法令未禁止之情況下，組成個體查核人員與集團查核團隊合作時，應提供攸關之查核工作底 稿予集團查核團隊", "集團查核團隊應依審計準則300號「財務報表查核之規劃」之規定，訂定集團整體查核策略及 集團查核計畫", "就集團查核而言，對於所辨認科目餘額或交易類別之重大不實表達風險，集團查核團隊不得自 行採取適當之因應，而須組成個體查核人員之參與"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00225', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', 'A金融控股公司的簽證會計師，在進行實地查核工作時，接獲告發信函，詳細描述其告發的舞弊 內容及巨額金額。此時簽證會計師應採取下列何項行動？', '["金融監督管理委員會於金融控股公司內部控制及稽核制度實施辦法中規定，金融控股公司應建 立吹哨者揭弊及因應機制；因而，會計師應該立即向金融監督管理委員會報告", "立即與公司內部治理單位及管理階層聯繫，提醒立即進行舞弊評估，並保持專業警覺性，擴大 可能舞弊風險的查核深度及範圍", "因為A金控公司已經建立有吹哨者揭弊因應機制，會計師應拒絕接受並立即轉請告發者向該機 制告發", "會計師應秉持專業的道德精神，立即向司法單位舉報該項告發內容，並保持專業警覺性，擴大 可能舞弊風險的查核深度及範圍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00226', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '當查核目的為測試應付帳款餘額是否低估，下列何者不適合界定為母體？', '["應付帳款明細", "期後付款", "未入帳之驗收單", "當期已付款發票"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00227', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依審計準則550號「關係人」規定，所謂公平交易，係指符合下列那些條件之交易？① 買賣雙方', '["買賣雙方均有成交意願", "買賣雙方目前雖無成交意願，惟在可 預見之未來，有極大可能性成交", "買賣雙方於協商交易之條款及條件時各自追求自身最佳利益", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00228', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '有關查核人員辨認與評估重大不實表達風險是否為顯著風險時所考量之事項，下列敘述何者錯誤？', '["該項風險與重大關係人交易有關", "該項風險的財務資訊衡量涉及高度的主觀判斷性事項", "與該項風險有關之控制是否有效執行", "該項風險是否涉及非例行性重大交易"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00229', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '下列何種情況可能會導致存貨帳列數量與實際庫存數量不一致？①平均成本法公式計算錯誤', '["盤點盈虧未調整", "存貨報廢或失竊未記錄", "以目的地交貨為條件之銷貨", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "bdbb8bbc2489", "answer_pdf_sha1": "6703af65ca29", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
